package com.marianaalra.booklog.di

import com.marianaalra.booklog.data.local.dao.UserDao
import com.marianaalra.booklog.data.remote.api.ApiService
import com.marianaalra.booklog.data.remote.api.RetrofitClient
import com.marianaalra.booklog.data.repository.impl.AuthRemoteRepositoryImpl
import com.marianaalra.booklog.data.repository.remote.BookRemoteRepository
import com.marianaalra.booklog.data.repository.remote.ColeccionRemoteRepository
import com.marianaalra.booklog.data.repository.remote.LecturaColeccionRemoteRepository
import com.marianaalra.booklog.data.repository.remote.NoteRemoteRepository
import com.marianaalra.booklog.data.repository.remote.QuoteRemoteRepository
import com.marianaalra.booklog.data.repository.remote.SerieRemoteRepository

/**
 * MÓDULO DE INYECCIÓN DE DEPENDENCIAS
 * 
 * Este módulo provee todas las instancias necesarias para usar la API remota.
 * 
 * Puedes usar esto con:
 * - Hilt (recomendado para Android moderno)
 * - Koin
 * - Dagger
 * - Manual (como se muestra aquí)
 */

object RemoteModule {

    /**
     * Obtener la instancia de ApiService (singleton de Retrofit)
     */
    fun provideApiService(): ApiService {
        return RetrofitClient.apiService
    }

    /**
     * Proveer AuthRemoteRepository (login/registro)
     */
    fun provideAuthRemoteRepository(
        apiService: ApiService,
        userDao: UserDao
    ): AuthRemoteRepositoryImpl {
        return AuthRemoteRepositoryImpl(apiService, userDao)
    }

    /**
     * Proveer BookRemoteRepository
     */
    fun provideBookRemoteRepository(
        apiService: ApiService = provideApiService()
    ): BookRemoteRepository {
        return BookRemoteRepository(apiService)
    }

    /**
     * Proveer SerieRemoteRepository
     */
    fun provideSerieRemoteRepository(
        apiService: ApiService = provideApiService()
    ): SerieRemoteRepository {
        return SerieRemoteRepository(apiService)
    }

    /**
     * Proveer ColeccionRemoteRepository
     */
    fun provideColeccionRemoteRepository(
        apiService: ApiService = provideApiService()
    ): ColeccionRemoteRepository {
        return ColeccionRemoteRepository(apiService)
    }

    /**
     * Proveer NoteRemoteRepository
     */
    fun provideNoteRemoteRepository(
        apiService: ApiService = provideApiService()
    ): NoteRemoteRepository {
        return NoteRemoteRepository(apiService)
    }

    /**
     * Proveer QuoteRemoteRepository
     */
    fun provideQuoteRemoteRepository(
        apiService: ApiService = provideApiService()
    ): QuoteRemoteRepository {
        return QuoteRemoteRepository(apiService)
    }

    /**
     * Proveer LecturaColeccionRemoteRepository
     */
    fun provideLecturaColeccionRemoteRepository(
        apiService: ApiService = provideApiService()
    ): LecturaColeccionRemoteRepository {
        return LecturaColeccionRemoteRepository(apiService)
    }
}

/**
 * EJEMPLO DE USO (en tu Activity/Fragment):
 * 
 * val authRemote = RemoteModule.provideAuthRemoteRepository(
 *     apiService = RemoteModule.provideApiService(),
 *     userDao = database.userDao()
 * )
 * 
 * val bookRemote = RemoteModule.provideBookRemoteRepository()
 * 
 * // En tu ViewModel:
 * class MyViewModel(
 *     private val authRemote: AuthRemoteRepositoryImpl,
 *     private val bookRemote: BookRemoteRepository
 * ) : ViewModel() {
 *     // ... tu código
 * }
 */

package com.marianaalra.booklog.domain.util
/** * Sealed class que encapsula estados de operaciones remotas/asincrónicas. * Permite manejar Success, Error y Loading de manera type-safe. */ sealed class Resource<out T> { data class Success<T>(val data: T) : Resource<T>() data class Error(val exception: Exception) : Resource<Nothing>() object Loading : Resource<Nothing>()
/** * Ejecuta un bloque de código si el resultado es Success. */ inline fun <R> map(block: (T) -> R): Resource<R> = when (this) { is Success -> Success(block(data)) is Error -> Error(exception) is Loading -> Loading }
/** * Retorna el dato si es Success, null en caso contrario. */ fun getOrNull(): T? = (this as? Success)?.data
/** * Retorna true si es Success. */ fun isSuccess(): Boolean = this is Success
/** * Retorna true si es Error. */ fun isError(): Boolean = this is Error
/** * Retorna true si es Loading. */ fun isLoading(): Boolean = this is Loading }

package com.marianaalra.booklog.example

import android.util.Log
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.marianaalra.booklog.data.local.dao.UserDao
import com.marianaalra.booklog.data.repository.impl.AuthRemoteRepositoryImpl
import com.marianaalra.booklog.data.repository.remote.BookRemoteRepository
import com.marianaalra.booklog.domain.model.Book
import com.marianaalra.booklog.domain.model.UserDomain
import com.marianaalra.booklog.domain.util.Resource
import kotlinx.coroutines.launch

/**
 * EJEMPLO COMPLETO: Cómo integrar los Repositorios Remote en tu ViewModel
 * 
 * Este archivo muestra:
 * 1. Login remoto con AuthRemoteRepositoryImpl
 * 2. Obtener libros del usuario con BookRemoteRepository
 * 3. Crear nuevo libro
 * 4. Manejo de Resource<T> para estados (Success, Error, Loading)
 */

class ExampleBookViewModel(
    private val authRemote: AuthRemoteRepositoryImpl,
    private val bookRemote: BookRemoteRepository,
    private val userDao: UserDao
) : ViewModel() {

    // Estados de UI (en tu app usarías StateFlow o LiveData)
    private var currentUser: UserDomain? = null
    private var books: List<Book> = emptyList()
    private var isLoading = false

    // ==================== LOGIN REMOTO ====================

    fun loginRemoto(correo: String, contrasena: String) {
        viewModelScope.launch {
            isLoading = true

            val result = authRemote.loginRemote(correo, contrasena)

            when (result) {
                is Resource.Success -> {
                    currentUser = result.data
                    Log.d("BookVM", "Login exitoso: ${currentUser?.nombreUsuario}")
                    // Aquí podrías navegar a la pantalla principal
                    loadBooks()
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error login: ${result.exception.message}")
                    // mostrarError(result.exception.message)
                }
                is Resource.Loading -> {
                    Log.d("BookVM", "Logging in...")
                }
            }

            isLoading = false
        }
    }

    // ==================== REGISTRO REMOTO ====================

    fun registroRemoto(nombreUsuario: String, correo: String, contrasena: String) {
        viewModelScope.launch {
            isLoading = true

            val result = authRemote.registerRemote(nombreUsuario, correo, contrasena)

            when (result) {
                is Resource.Success -> {
                    currentUser = result.data
                    Log.d("BookVM", "Registro exitoso: ${currentUser?.nombreUsuario}")
                    loadBooks()
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error registro: ${result.exception.message}")
                }
                is Resource.Loading -> {}
            }

            isLoading = false
        }
    }

    // ==================== OBTENER LIBROS ====================

    fun loadBooks() {
        if (currentUser == null) {
            Log.e("BookVM", "Usuario no autenticado")
            return
        }

        viewModelScope.launch {
            isLoading = true

            val result = bookRemote.getBooksByUsuarioId(currentUser!!.id)

            when (result) {
                is Resource.Success -> {
                    books = result.data
                    Log.d("BookVM", "Se cargaron ${books.size} libros")
                    // Aquí actualizarías tu UI con los libros
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error al cargar libros: ${result.exception.message}")
                }
                is Resource.Loading -> {
                    Log.d("BookVM", "Cargando libros...")
                }
            }

            isLoading = false
        }
    }

    // ==================== OBTENER LIBROS POR ESTADO ====================

    fun loadBooksByEstado(estado: String) {
        if (currentUser == null) return

        viewModelScope.launch {
            val result = bookRemote.getBooksByEstado(currentUser!!.id, estado)

            when (result) {
                is Resource.Success -> {
                    books = result.data
                    Log.d("BookVM", "Libros con estado '$estado': ${books.size}")
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error: ${result.exception.message}")
                }
                is Resource.Loading -> {}
            }
        }
    }

    // ==================== BUSCAR LIBROS ====================

    fun searchBooks(titulo: String) {
        if (currentUser == null) return

        viewModelScope.launch {
            val result = bookRemote.searchByTitulo(currentUser!!.id, titulo)

            when (result) {
                is Resource.Success -> {
                    books = result.data
                    Log.d("BookVM", "Búsqueda encontró ${books.size} resultados")
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error búsqueda: ${result.exception.message}")
                }
                is Resource.Loading -> {}
            }
        }
    }

    // ==================== CREAR LIBRO ====================

    fun crearLibro(
        titulo: String,
        autor: String,
        formato: String,
        rutaArchivo: String,
        nombreArchivo: String
    ) {
        if (currentUser == null) return

        viewModelScope.launch {
            // Crear objeto Book con los datos
            val nuevoLibro = Book(
                usuarioId = currentUser!!.id,
                title = titulo,
                author = autor,
                fileFormat = formato,
                fileUri = rutaArchivo,
                nombreArchivo = nombreArchivo,
                status = "PENDIENTE",
                progress = 0f
            )

            val result = bookRemote.createBook(nuevoLibro)

            when (result) {
                is Resource.Success -> {
                    val libroCreado = result.data
                    Log.d("BookVM", "Libro creado con ID: ${libroCreado.id}")
                    // Recargar lista de libros
                    loadBooks()
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error al crear libro: ${result.exception.message}")
                }
                is Resource.Loading -> {}
            }
        }
    }

    // ==================== ACTUALIZAR PROGRESO ====================

    fun actualizarProgreso(bookId: Long, progreso: Float) {
        viewModelScope.launch {
            val result = bookRemote.updateBookProgress(bookId, progreso)

            when (result) {
                is Resource.Success -> {
                    Log.d("BookVM", "Progreso actualizado: $progreso%")
                    // Actualizar en lista local
                    books = books.map {
                        if (it.id == bookId) it.copy(progress = progreso) else it
                    }
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error: ${result.exception.message}")
                }
                is Resource.Loading -> {}
            }
        }
    }

    // ==================== ELIMINAR LIBRO ====================

    fun eliminarLibro(bookId: Long) {
        viewModelScope.launch {
            val result = bookRemote.deleteBook(bookId)

            when (result) {
                is Resource.Success -> {
                    Log.d("BookVM", "Libro eliminado")
                    // Recargar lista
                    loadBooks()
                }
                is Resource.Error -> {
                    Log.e("BookVM", "Error: ${result.exception.message}")
                }
                is Resource.Loading -> {}
            }
        }
    }

    // ==================== LOGOUT ====================

    fun logout() {
        viewModelScope.launch {
            authRemote.logout()
            currentUser = null
            books = emptyList()
            Log.d("BookVM", "Logout completado")
        }
    }

    // ==================== GETTERS ====================

    fun getCurrentUser() = currentUser
    fun getBooks() = books
    fun isLoading() = isLoading
}

